// Align for better DMA
static constexpr uint32_t ALIGN_ELEMS = 256;
// Maximum blocks to avoid oversubscription
static constexpr uint32_t MAX_BLOCKS = 24;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard2dSquareInputAsymmetricKernelDilatedPaddedCustomTilingData tiling;

    // Shapes
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const uint32_t N  = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t C  = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t H  = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t W  = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));
    const uint32_t Cin  = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(1));
    const uint32_t KH   = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(2));
    const uint32_t KW   = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(3));

    // Attributes
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t stride_h   = attrs->HasAttr(0) ? *attrs->GetAttrPointer<int32_t>(0) : 1;
    const int32_t stride_w   = attrs->HasAttr(1) ? *attrs->GetAttrPointer<int32_t>(1) : 1;
    const int32_t pad_top    = attrs->HasAttr(2) ? *attrs->GetAttrPointer<int32_t>(2) : 2;
    const int32_t pad_bottom = attrs->HasAttr(3) ? *attrs->GetAttrPointer<int32_t>(3) : 2;
    const int32_t pad_left   = attrs->HasAttr(4) ? *attrs->GetAttrPointer<int32_t>(4) : 4;
    const int32_t pad_right  = attrs->HasAttr(5) ? *attrs->GetAttrPointer<int32_t>(5) : 4;
    const int32_t dilation_h = attrs->HasAttr(6) ? *attrs->GetAttrPointer<int32_t>(6) : 2;
    const int32_t dilation_w = attrs->HasAttr(7) ? *attrs->GetAttrPointer<int32_t>(7) : 3;

    // Output dims
    const uint32_t eff_kh = static_cast<uint32_t>(dilation_h) * (KH - 1u) + 1u;
    const uint32_t eff_kw = static_cast<uint32_t>(dilation_w) * (KW - 1u) + 1u;
    const uint32_t outH = static_cast<uint32_t>((static_cast<int64_t>(H) + pad_top + pad_bottom - eff_kh) / stride_h + 1);
    const uint32_t outW = static_cast<uint32_t>((static_cast<int64_t>(W) + pad_left + pad_right - eff_kw) / stride_w + 1);

    // K = Cin * KH * KW
    const uint32_t K = Cin * KH * KW;

