static inline int64_t out_dim(int64_t in, int64_t pad0, int64_t pad1, int64_t k_eff, int64_t stride)
{
    return (in + pad0 + pad1 - k_eff) / stride + 1;
}

at::Tensor conv2d_std_asym_dilated_impl_npu(const at::Tensor& x, const at::Tensor& weight,
                                            int64_t stride_h = 1, int64_t stride_w = 1,
                                            int64_t pad_top = 2, int64_t pad_bottom = 2,
                                            int64_t pad_left = 4, int64_t pad_right = 4,
                                            int64_t dilation_h = 2, int64_t dilation_w = 3)
{
    TORCH_CHECK(x.dim() == 4, \"x must be 4D NCHW\");
    TORCH_CHECK(weight.dim() == 4, \"weight must be 4D OIHW\");
    auto N = x.size(0);
    auto C = x.size(1);
    auto H = x.size(2);
    auto W = x.size(3);
    auto Cout = weight.size(0);
    auto KH = weight.size(2);
    auto KW = weight.size(3);

    int64_t eff_kh = dilation_h * (KH - 1) + 1;
    int64_t eff_kw = dilation_w * (KW - 1) + 1;
    int64_t outH = out_dim(H, pad_top, pad_bottom, eff_kh, stride_h);
    int64_t outW = out_dim(W, pad_left, pad_right, eff_kw, stride_w);

    at::Tensor result = at::empty({N, Cout, outH, outW}, x.options());
    EXEC_NPU_CMD(aclnnConvStandard2dSquareInputAsymmetricKernelDilatedPaddedCustom,
                 x, weight,
                 static_cast<int>(stride_h), static_cast<int>(stride_w),
                 static_cast<int>(pad_top), static_cast<int>(pad_bottom),
                 static_cast<int>(pad_left), static_cast<int>(pad_right),
                 static_cast<int>(dilation_h), static_cast<int>(dilation_w),
                 result);
